import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormLabel, Grid } from '@material-ui/core';
import { INVProductPackagingCount, INVPackagingDisplay } from '../../../../INVProducts';


const style = theme => ({
    root: {
        margin: 10,
        marginTop : 20,
    },
    packagingCount : {
        marginTop : 20,
    }
})
class _INVNewBrandPackaging extends Component {
    constructor(props) {
        super(props);
        this.state={
            selectedPackaging : []
        }
    }
    
    render() {
        const {classes, productPackages, productPackagings} = this.props;
        const { selectedPackaging } = this.state;
        return (
            <div className={classes.root}>
                <div>
                    <FormLabel style={{maringBottom : 10}}>Select Packaging</FormLabel>
                    <Grid container spacing={2}>                    
                        {productPackagings && productPackagings.map(
                            (packaging, index)=>
                                <Grid key={index} item xs={6} sm={3} md={3} lg={2} xl={2}>
                                    <INVPackagingDisplay
                                        packages={productPackages}
                                        packaging={packaging}
                                        selectable
                                        selected={selectedPackaging && selectedPackaging._id === packaging._id}
                                        onSelectCallback={selectedPackaging=>this.setState({selectedPackaging})}
                                    />
                                </Grid>
                        )}
                    </Grid>
                </div>
                {selectedPackaging && <div className={classes.packagingCount}>
                    <FormLabel style={{maringBottom : 10}}>Packaging Quantity</FormLabel>
                    <INVProductPackagingCount
                        packaging={selectedPackaging}
                        />
                </div>}
            </div>
        );
    }
}


_INVNewBrandPackaging.propTypes = {
    classes : PropTypes.object.isRequired,
    productPackages : PropTypes.array,
    productPackagings : PropTypes.array,
};
const mapStateToProps = state => ({
    state
})


export const INVNewBrandPackaging = connect(mapStateToProps)(withStyles(style)(_INVNewBrandPackaging));
export {INVNewBrandPackaging as default}