import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { StageHeaderPlane, SimplePagination, appActions, alertAction } from '../../utils';
import { INVSupplierList } from '../INVSupplierList';
import { invSupplierStrings } from '../config';
import { invSupplierActions } from '../actions';
import { FormLabel } from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _INVSupplierSearch extends Component {
    constructor(props) {
        super(props);
        this.state={
            suppliers : null,
            minId : null,
            maxId : null,
            rows : 20,
            skip : 0
        }
    }
    searchSupplierMinMaxId(keyword){
        const {dispatch} = this.props;
        invSupplierActions.searchSupplierMinMaxId(keyword, (done, {minId, maxId}, message)=>{
            this.setState({minId, maxId});
        })(dispatch);
    }
    searchSupplier(start, nav){
        const {dispatch} = this.props;
        const {rows, skip, keyword} = this.state;
        if(!String(keyword).trim())
            return;
        let newSkip;
        if(start){
            newSkip = 0;
        }else{
            const prevSkip = skip - rows;
            const nextSkip = skip + rows;
            newSkip = nav === "backward" ? prevSkip : nextSkip
        }
        invSupplierActions.searchSuppliers(
            keyword,
            rows, 
            newSkip, 
            (done, result, message)=>{
                if(done){
                    this.setState({skip : newSkip})
                    this.configurePagination(result);
                }
        })(dispatch);
    }
    configurePagination(result){
        if(result.length !== 0){
            const newLastId = result[result.length - 1]._id;
            const newFirstId = result[0]._id;
            this.setState({suppliers : result, lastId : newLastId, firstId : newFirstId})
        }
    }
    pageNextBtnClick(){
        this.searchSupplier(false);
    }
    pagePrevBtnClick(){
        this.searchSupplier(false, "backward");
    }
    searchAction(keyword){
        keyword = String(keyword).trim();
        const {dispatch} = this.props;
        if(!keyword || keyword === ""){
            appActions.showSnackbar(
                alertAction.error("Search keyword is empty!")
            )(dispatch);
        }else{
            this.setState({keyword}, ()=>{
                this.searchSupplierMinMaxId(keyword);
                this.searchSupplier(true);
            });
        }
    }
    onSearchWordChange(keyword){
        keyword = String(keyword).trim();
        if(!keyword || keyword === ""){
            this.setState({keyword : null, suppliers : null});
        }
    }
    onRowSelection = supplier => () => {
        const {onSelectionCallback} = this.props;
        if(onSelectionCallback) onSelectionCallback(supplier);
    }
    render() {
        const {
            classes,
        } = this.props;
        const {skip, rows, minId, maxId, lastId, suppliers} = this.state;
        return (
            <div className={classNames("animated", "zoomIn", classes.root)}>
                <FormLabel>Select Brand Company/Supplier</FormLabel>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        visible={true}
                        searchActions={this.searchAction.bind(this)}
                        onChangeCallback={this.onSearchWordChange.bind(this)}
                        />
                </div>
                <INVSupplierList
                    tableProps={{
                        elevation : 0
                    }}
                    suppliers={suppliers || []}
                    tableProps={{
                        rowAction : this.onRowSelection.bind(this),
                    }}
                    {...this.props.supplierListProps}
                />
                <div>
                <SimplePagination
                        classes={{
                            btn : classes.pageBtn,
                            prevBtn : classes.pagePrevBtn,
                            nextBtn : classes.pageNextBtn,
                            root : classes.pageRoot
                        }}
                        prevBtnProps={{
                            disabled : skip === 0
                        }}
                        nextBtnProps={{
                            disabled : !suppliers || suppliers.length < rows || minId === lastId
                        }}
                        prevBtnClick={this.pagePrevBtnClick.bind(this)}
                        nextBtnClick={this.pageNextBtnClick.bind(this)}/>
                </div>
            </div>
        );
    }
}


_INVSupplierSearch.propTypes = {
    classes : PropTypes.object.isRequired,
    onSelectionCallback : PropTypes.func,
    supplierListProps : PropTypes.shape(INVSupplierList.propTypes),
};
const mapStateToProps = ({invSupplierReducer}) => ({
    [invSupplierStrings.suppliers] : invSupplierReducer[invSupplierStrings.suppliers]
})


export const INVSupplierSearch = connect(mapStateToProps)(withStyles(style)(_INVSupplierSearch));
export {INVSupplierSearch as default}