import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, FormDisplay, MyDialog, ObjectHighlightBoard} from '../../../utils';
import { routeNamesInventory } from '../../../routeNames';
import { invSupplierStrings } from '../../config';
import {INVSupplierSearch} from '../../INVSupplierSearch';
import { INVButton } from '../../../Includes';
import { Grid, FormLabel } from '@material-ui/core';
import { 
    invProductStrings, invProductActions,
    INVProductPackagingCount, INVPackagingDisplay, INVDrugNameSelection 
} from "../../../INVProducts";
import INVNewBrandPackaging from './INVNewBrandPackaging/INVNewBrandPackaging';

const style = theme => ({
    root: {
    },
    supplierStyle : {
        backgroundColor : theme.colors.background,
    },
    supplierHeaderStyle : {

    },
    supplierTextStyle : {
        
    },
    formContainer : {
        padding :20,
        [theme.breakpoints.up("md")] : {
            padding : "20px 100px",
        }
    },
    requireSupplier : {
        padding : 100,
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
    },
})
class _INVNewBrand extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        this.state = {
            phase : 1,
            supplier : null,
            supplierDialog : false
        }
        headerActions({
            [headerStrings.headerTitle] : "NEW BRAND",
            [headerStrings.backButtonAction] : ()=>{},
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Brands", path : routeNamesInventory.supplierBrands},
            {name : "New Brand", path : routeNamesInventory.newSupplierBrand}
        ])(dispatch);
        this.formConfig = [
            {name : "name", label : "Brand Name", placeholder : "Brand Name", required : true},
            {name : "tagId", label : "Tag", type : "select"},
            {name : "categoryId", label : "Categories", type : "select"},
            {name : "formId", label : "Forms", type : "select"},
        ]
    }
    componentDidMount() {
        const {
            dispatch,
            [invProductStrings.productCats] : productCategories,
            [invProductStrings.productForms] : productForms,
            [invProductStrings.productDescriptions] : productDescriptions,
            [invProductStrings.productPackagings] : productPackagings,
            [invProductStrings.productPackages] : productPackages,
            [invProductStrings.productTags] : productTags,
        } = this.props;
        if(!productCategories) invProductActions.getProductCats()(dispatch);
        if(!productForms) invProductActions.getProductForms()(dispatch);
        if(!productDescriptions) invProductActions.getProductDescriptions()(dispatch);
        if(!productPackagings) invProductActions.getProductPackagings()(dispatch);
        if(!productTags) invProductActions.getProductTags()(dispatch);
        if(!productPackages) invProductActions.getProductPackages()(dispatch);
    }
    adjustFormConfig(){
        const {
            [invSupplierStrings.suppliers] : companies,
            [invProductStrings.productCats] : categories,
            [invProductStrings.productForms] : forms,
            [invProductStrings.productDescriptions] : descriptions,
            [invProductStrings.productPackagings] : packagings,
            [invProductStrings.productTags] : tags,
        } = this.props;
        
        this.formConfig = this.formConfig.map(item=>{
            switch(item.name){
                case "companyId" : 
                    if(companies) item.options = companies; break;
                case "formId" :
                    if(forms) item.options = forms; break;
                case "tagId" : 
                    if(tags) item.options = tags; break;
                case "categoryId" : 
                    if(categories) item.options = categories; break;
                case "packagingId" : 
                    if(packagings) item.options = packagings; break;
            }
            return item;
        })
    }
    nameMapper(name){
        switch(name){
            case "_id" : return "ID";
            case "address" : return "Address";
            case "name" : return "Name";
            case "email" : return "Email";
            case "phone" : return "Phone";
            default : return name;
        }
    }
    render() {
        const {
            classes,
            [invProductStrings.productPackagings] : productPackagings,
            [invProductStrings.productPackages] : productPackages,
        } = this.props;
        const {phase, supplier, supplierDialog, selectedPackaging, drugNameSearchDialog} = this.state;
        this.adjustFormConfig();
        return (
            <div className={classNames("animated", "zoomIn", classes.root)}>
                {supplier && <div>
                    <ObjectHighlightBoard
                        classes={{
                            root : classes.supplierStyle,
                            text : classes.supplierTextStyle,
                        }}
                        nameMapper={this.nameMapper}
                        objectData={supplier}
                        skip={["companyId"]}
                        gridItemProps={{
                            xs : 12, sm : 6, md : 4, lg : 3
                        }}
                        />
                </div>}
                {true ? //supplier ? 
                    (phase === 1 && <div className={classes.formContainer}>
                        <FormDisplay
                            formName="NewBrand"
                            header="New Brand"
                            formConfig={this.formConfig}
                            />
                        <INVNewBrandPackaging
                            productPackages={productPackages}
                            productPackagings={productPackagings}
                            />
                        <INVDrugNameSelection/>
                    </div>) : 
                    <div className={classes.requireSupplier}>
                        <INVButton
                            onClick={()=>this.setState({supplierDialog : true})}
                            type="highlight"
                            >Select Supplier/Company</INVButton>
                    </div>}

                <MyDialog open={supplierDialog}
                 close={()=>this.setState({supplierDialog : false})}>
                    <INVSupplierSearch
                        onSelectionCallback={supplier=>this.setState({supplier, supplierDialog : false})}/>
                </MyDialog>
                <MyDialog open={drugNameSearchDialog}
                    close={()=>this.setState({drugNameSearchDialog : false})}>
                        
                    </MyDialog>
            </div>
        );
    }
}


_INVNewBrand.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.productDescriptions] : invProductReducer[invProductStrings.productDescriptions],
    [invProductStrings.productCats] : invProductReducer[invProductStrings.productCats],
    [invProductStrings.productForms] : invProductReducer[invProductStrings.productForms],
    [invProductStrings.productTags] : invProductReducer[invProductStrings.productTags],
    [invProductStrings.productPackagings] : invProductReducer[invProductStrings.productPackagings],
    [invProductStrings.productPackages] : invProductReducer[invProductStrings.productPackages],
})


export const INVNewBrand = connect(mapStateToProps)(withStyles(style)(_INVNewBrand));
export {INVNewBrand as default}